  "translated_query_code": "import java.time.LocalDate;
import java.util.List;
import org.bson.Document;
import org.springframework.data.domain.Sort;
import org.springframework.data.mongodb.core.MongoTemplate;
import org.springframework.data.mongodb.core.aggregation.Aggregation;
import org.springframework.data.mongodb.core.query.Criteria;
import org.springframework.data.mongodb.core.query.Query;

class MongoQueryEntrypoint {
    static List<OrderLine> query1(MongoTemplate ctx) {
        LocalDate from = LocalDate.of(2014, 12, 20);
        LocalDate to = LocalDate.of(2014, 12, 31);
        Query query = Query.query(Criteria.where("pickingCompletedWhen").gte(from).lte(to));
        return ctx.find(query, OrderLine.class);
    }

    static List<Order> query2(MongoTemplate ctx) {
        Query query = Query.query(Criteria.where("customerId").is(1));
        return ctx.find(query, Order.class);
    }

    static List<Document> query3(MongoTemplate ctx) {
        Aggregation aggregation = Aggregation.newAggregation(
            OrderLine.class,
            Aggregation.group("taxRate").count().as("count"),
            Aggregation.project("count").and("taxRate").previousOperation(),
            Aggregation.sort(Sort.Direction.DESC, "count")
        );
        return ctx.aggregate(aggregation, OrderLine.class, Document.class).getMappedResults();
    }

    static List<OrderLine> query4(MongoTemplate ctx) {
        Query query = new Query().with(Sort.by(Sort.Direction.DESC, "quantity")).limit(50);
        return ctx.find(query, OrderLine.class);
    }

    static List<Document> query5(MongoTemplate ctx) {
        Query query = new Query();
        query.fields().include("orderLineId", "quantity");
        return ctx.find(query, Document.class, "orderLines");
    }
}"
